  import java.util.Date;
  import sailpoint.object.IdentityRequest;
  import sailpoint.api.SailPointContext;
  import sailpoint.object.Filter;
  import sailpoint.object.QueryOptions;
  import java.util.List;
  import sailpoint.object.IdentityRequestItem;
  import java.nio.file.Path;
  import java.nio.file.Files;
  import java.nio.file.Paths;
  import java.nio.file.LinkOption;
  import java.nio.charset.Charset;

	Path outPath = Paths.get("\\\\andc1wapp0147.ds.sjhs.com\\AppAggregation\\rehireReport-08-14-2023.csv"); //Absolute Path of Output File

	BufferedWriter bw = Files.newBufferedWriter(outPath, Charset.forName("UTF-8"));

	bw.write("IdentityRequest|RequestItemApps|RequestItemsHasAD");

	

  Date date = new Date(1691494140000L);
  StringBuilder sb = new StringBuilder();
  sb.append("IdentityRequest" +" | "+ "RequestItemApps" + " | " + "RequestItemsHasAD" + "\n");
 
  QueryOptions qo = new QueryOptions() ;
  qo.addFilter(Filter.eq("type", "Rehire Lifecycle Event"));//   
  qo.addFilter(Filter.gt("created",date));

  List identityRequestList = context.getObjects(IdentityRequest.class,qo);
   for(IdentityRequest identityRequest: identityRequestList)
   {      
      List requestItemAppsList = new ArrayList();
      boolean requestItemsHasAD;
      String requestNumber = identityRequest.getName();
 
    List items =identityRequest.getItems();
	for(IdentityRequestItem item:items){
      String appName = item.getApplication();
        if(!requestItemAppsList.contains(appName)){
     		requestItemAppsList.add(appName);
        }
	}
   
     
     for(String name :requestItemAppsList) {
        if(name.contains("AD-")){
                        requestItemsHasAD = true;
        }
     }
     
     String str = requestItemAppsList.toString();
      String requestItemApps = str.substring(1, str.length()-1);
     sb.append(requestNumber +" | "+ requestItemApps + " | "+ requestItemsHasAD + "\n");
     bw.newLine();
     bw.write(requestNumber +" | "+ requestItemApps + " | "+ requestItemsHasAD);
  }
  return sb.toString();
